// FR-01: Account Registration — DOM Check Suite
// Generated by: test-execution-assistant skill
//
// Instructions:
//   1. Navigate browser to: http://localhost:5173/register
//   2. Open DevTools: F12 → Console tab
//   3. Paste this entire script content and press Enter
//   4. Screenshot the console output (1 screenshot for all DOM checks)
//   5. Copy the printed summary and paste into Phase B prompt
// =============================================================================

(function FR01DOMChecks() {
  "use strict";

  let pass = 0,
    fail = 0;
  const results = [];

  function check(tcId, description, expected, actualFn) {
    let actual, status;
    try {
      actual = actualFn();
      const ok =
        expected === "EXISTS"
          ? actual !== null && actual !== undefined && actual !== "NOT_FOUND"
          : String(actual) === String(expected);
      status = ok ? "PASS" : "FAIL";
    } catch (e) {
      actual = "ERROR: " + e.message;
      status = "FAIL";
    }
    status === "PASS" ? pass++ : fail++;
    results.push({ tcId, description, expected, actual, status });
  }

  // ── FR01-specific DOM checks ────────────────────────────

  // DOM-H1: Exactly 1 <h1> tag (per FR-21 — all web pages)
  check("FR01-DOM-H1", "Page has exactly 1 <h1> tag (per FR-21)", "1", () =>
    String(document.querySelectorAll("h1").length),
  );

  // DOM-EMAIL: Email input type="email" (per FR-22)
  check(
    "FR01-DOM-EMAIL",
    'Email input has type="email" (per FR-22)',
    "email",
    () => {
      const el =
        document.querySelector(
          'input[name="email"], input[autocomplete="email"]',
        ) || document.querySelector('input[type="email"]');
      return el ? el.type : "No email field found or input type is not email";
    },
  );

  // DOM-PW: Password input type="password" (per FR-22)
  check(
    "FR01-DOM-PW",
    "Form must have Password & Confirm Password inputs (per FR-22)",
    "2 password fields",
    () => {
      const pws = document.querySelectorAll('input[type="password"]');
      if (pws.length === 0) return "No password fields found";
      if (pws.length === 1) return "Only 1 password field found";
      return `Found ${pws.length} field(s) - Has Password and Confirm Password`;
    },
  );

  // DOM-STAR: Required fields have * label marker (per FR-22)
  check(
    "FR01-DOM-STAR",
    "Required fields have * in label (per FR-22)",
    "Has * markers",
    () => {
      const labels = Array.from(document.querySelectorAll("label"));
      const stars = labels.filter((l) => l.textContent.trim().includes("*"));
      if (stars.length > 0) return "Has * markers";
      return "0 labels with *";
    },
  );

  // XSS Escaping Check (FR01-EP-020)
  check("FR01-EP-020", "XSS Payload is escaped and not executed", "true", () =>
    String(!document.body.innerHTML.includes("<script>")),
  );

  // ── Print Summary ───────────────────────────────────────────────
  console.log(
    "%c━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━",
    "font-weight: bold",
  );
  console.log(
    "%c FR-01 DOM CHECK RESULTS",
    "font-weight: bold; font-size: 14px",
  );
  console.log(
    "%c━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━",
    "font-weight: bold",
  );

  results.forEach((r) => {
    const color =
      r.status === "PASS"
        ? "color: green; font-weight: bold"
        : "color: red; font-weight: bold";
    console.log(
      `%c[${r.status}] %c${r.tcId} — ${r.description}`,
      color,
      "color: inherit",
    );
    console.log(`       Expected: ${r.expected} | Actual: ${r.actual}`);
  });

  console.log(
    "%c━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━",
    "font-weight: bold",
  );
  console.log(
    `TOTAL: %c${pass} PASS%c | %c${fail} FAIL`,
    "color: green; font-weight: bold",
    "color: inherit",
    "color: red; font-weight: bold",
  );
})();
